"use client";

import React, { useState } from "react";
import { useParams } from "next/navigation";
import { Upload, X, MapPin, Tag, Info, Calendar, CheckCircle } from "lucide-react";
// Assuming these paths and structures are correct based on your previous input
import { lostItems } from "@/app/data/lostitem";
import { foundItems } from "@/app/data/founditem";

const ClaimItemPage = () => {
  // 1. SAFE PARAMETER RETRIEVAL
  const params = useParams();
  // Ensure 'id' is extracted only if 'params' exists, and convert to string for strict comparison
  const id = params?.id ? String(params.id) : null; 

  // 2. ROBUST ITEM LOOKUP
  const item = id 
    ? lostItems.find((it) => String(it.id) === id) ||
      foundItems.find((it) => String(it.id) === id)
    : null;
    
  // --- Component State ---
  const [proofImages, setProofImages] = useState([]);
  const [claimText, setClaimText] = useState("");

  // 3. IMPROVED ERROR HANDLING
  if (!item)
    return (
      <div className="p-12 text-center text-2xl font-semibold text-gray-800 bg-gray-100 min-h-screen">
        Item Not Found. Please ensure the URL is correct.
      </div>
    );
    
  // --- Handlers (Logic remains correct) ---
  const handleFileUpload = (e) => {
    const files = Array.from(e.target.files);
    if (files.length + proofImages.length > 3) {
      alert("You can upload a maximum of 3 images.");
      return;
    }
    const imageFiles = files.filter((file) => file.type.startsWith("image/"));
    setProofImages([...proofImages, ...imageFiles]);
    e.target.value = null; 
  };

  const removeImage = (index) => {
    setProofImages(proofImages.filter((_, i) => i !== index));
  };
  
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!claimText.trim()) {
        alert("Please provide details on how you can prove ownership.");
        return;
    }
    // Submission logic placeholder
    console.log("Claim Submitted:", { claimText, proofImages });
    alert(`Claim for '${item.name}' submitted successfully! Awaiting review.`);
  };

  // --- Render (Design and corrected field item.name used) ---
  return (
    <div className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:px-8 bg-white min-h-screen font-sans">
      <h1 className="text-4xl font-black text-gray-900 mb-8 border-b-4 border-black pb-2 tracking-tight">
        CLAIM REVIEW: {item.name.toUpperCase()}
      </h1>

      <div className="grid lg:grid-cols-3 gap-10">

        {/* LEFT — ITEM VISUALS & METADATA (2/3 width) */}
        <div className="lg:col-span-2 space-y-8">

          {/* Item Image */}
          <div className="border border-gray-300 bg-gray-50 p-1 rounded-lg">
            <img
              src={item.image}
              alt={item.name}
              className="w-full h-[500px] object-cover rounded-md"
            />
          </div>

          {/* Item Information Panel */}
          <div className="bg-gray-100 p-6 rounded-lg border border-gray-300">
            <h3 className="text-2xl font-bold mb-4 flex items-center text-black">
              <Info className="w-5 h-5 mr-3 text-red-600" />
              Listing Specifications
            </h3>

            <p className="text-gray-700 mb-6 border-b border-gray-300 pb-4 italic">
              **Description:** {item.description}
            </p>

            <div className="grid grid-cols-3 gap-4 text-gray-800 text-sm">
              <div className="flex items-center space-x-2 p-2 bg-white border border-gray-300 rounded-md">
                <Tag className="w-4 h-4 text-green-600" />
                <p className="font-semibold">Category:</p>
                <span className="font-medium">{item.category}</span>
              </div>

              <div className="flex items-center space-x-2 p-2 bg-white border border-gray-300 rounded-md">
                <MapPin className="w-4 h-4 text-green-600" />
                <p className="font-semibold">Location:</p>
                <span className="font-medium">{item.location}</span>
              </div>

              <div className="flex items-center space-x-2 p-2 bg-white border border-gray-300 rounded-md">
                <Calendar className="w-4 h-4 text-green-600" />
                <p className="font-semibold">Date:</p>
                <span className="font-medium">{item.date}</span>
              </div>
            </div>
          </div>
        </div>
        
        {/* RIGHT — CLAIM FORM (1/3 width) */}
        <div className="lg:col-span-1 border-l-4 border-gray-900 pl-8 h-full sticky top-12">
          
          <h2 className="text-3xl font-black text-gray-900 mb-6">
            SUBMIT CLAIM EVIDENCE
          </h2>
          
          <form onSubmit={handleSubmit} className="space-y-6">
            
            {/* Ownership Details Textarea */}
            <div>
              <label htmlFor="claimText" className="font-bold block mb-2 text-gray-900 uppercase text-sm">
                Proof of Ownership Statement
              </label>
              <textarea
                id="claimText"
                rows={6}
                value={claimText}
                onChange={(e) => setClaimText(e.target.value)}
                className="w-full border-2 border-black rounded-none p-3 resize-none focus:outline-none focus:ring-2 focus:ring-red-500 shadow-md transition"
                placeholder="Detail unique markings, color deviations, or specific contents only the owner would know."
                required
              />
            </div>

            {/* Image Upload Section */}
            <div>
              <label className="font-bold block mb-2 text-gray-900 uppercase text-sm">
                Visual Evidence (Max 3)
              </label>

              <div className="relative border-2 border-dashed border-black rounded-none p-5 text-center bg-gray-100 cursor-pointer hover:bg-gray-200 transition">
                <input
                  type="file"
                  multiple
                  accept="image/*"
                  onChange={handleFileUpload}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  disabled={proofImages.length >= 3}
                />
                <Upload className="w-7 h-7 mx-auto text-black mb-1" />
                <p className="text-sm font-semibold text-black">
                  {proofImages.length >= 3 ? "3/3 Images Uploaded" : "Drag files or click to upload"}
                </p>
              </div>

              {/* Uploaded Image Previews */}
              {proofImages.length > 0 && (
                <div className="flex gap-3 flex-wrap mt-4">
                  {proofImages.map((file, idx) => (
                    <div
                      key={idx}
                      className="relative w-20 h-20 border-2 border-black overflow-hidden bg-white"
                    >
                      <img
                        src={URL.createObjectURL(file)}
                        alt={`Proof image ${idx + 1}`}
                        className="w-full h-full object-cover"
                      />

                      <button
                        type="button"
                        onClick={() => removeImage(idx)}
                        className="absolute top-0 right-0 bg-red-600 text-white p-1 transition hover:bg-red-700 focus:outline-none"
                        title="Remove image"
                      >
                        <X size={14} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Submission Button */}
            <button
              type="submit"
              className="w-full bg-black text-white py-3 mt-8 font-black text-lg border-2 border-black rounded-none hover:bg-red-600 hover:text-white transition duration-300 flex items-center justify-center space-x-2"
            >
              <CheckCircle className="w-5 h-5"/>
              <span>CONFIRM AND SUBMIT CLAIM</span>
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ClaimItemPage;